SELECT COUNT(*) FROM audit_logs

  AND tenant_id = #{tenantId}
  AND action = #{action}
  AND target_type = #{targetType}

SELECT log_id AS logId, tenant_id AS tenantId, user_id AS userId, username, action, target_type AS targetType, target_id AS targetId, detail, ip_address AS ipAddress, created_at AS createdAt FROM audit_logs
AND tenant_id = #{tenantId} AND action = #{action} AND target_type = #{targetType}
ORDER BY created_at DESC LIMIT #{limit} OFFSET #{offset}
